// Système Few-Shot Optimizer
const fewShotOptimizer = {
  // Analyser la tâche pour déterminer le nombre d'exemples optimal
  analyzeTask: (task) => {
    const complexity = calculateComplexity(task);
    const variability = calculateVariability(task);

    if (complexity < 3 && variability < 2) {
      return { method: 'zero-shot', examples: 0 };
    } else if (complexity < 5 && variability < 4) {
      return { method: 'one-shot', examples: 1 };
    } else if (complexity < 8) {
      return { method: 'few-shot', examples: '3-5' };
    } else {
      return { method: 'many-shot', examples: '7+' };
    }
  },

  // Générer le prompt optimal
  buildPrompt: (task, examples) => {
    const prompt = [];

    // Instructions
    prompt.push('Task: ' + task.description);
    prompt.push('Follow the exact format shown in the examples:\n');

    // Exemples avec structure claire
    examples.forEach((ex, i) => {
      prompt.push(`Example ${i+1}:`);
      prompt.push(`Input: ${ex.input}`);
      prompt.push(`Output: ${ex.output}`);
      prompt.push('---');
    });

    // Nouvelle requête
    prompt.push('Now process this:');
    prompt.push(`Input: ${task.input}`);
    prompt.push('Output:');

    return prompt.join('\n');
  }
};

// Example Quality Scorer
class ExampleQualityAnalyzer {
  scoreExampleSet(examples) {
    const scores = {
      diversity: this.calculateDiversity(examples),
      coverage: this.calculateCoverage(examples),
      clarity: this.calculateClarity(examples),
      progression: this.calculateProgression(examples),
      consistency: this.calculateConsistency(examples)
    };

    // Recommendations basées sur les scores
    const recommendations = [];

    if (scores.diversity < 0.7) {
      recommendations.push('Add more varied examples');
    }
    if (scores.coverage < 0.8) {
      recommendations.push('Missing edge cases');
    }
    if (scores.clarity < 0.9) {
      recommendations.push('Ambiguous outputs detected');
    }
    if (scores.progression < 0.6) {
      recommendations.push('Reorder: simple → complex');
    }
    if (scores.consistency < 0.95) {
      recommendations.push('Standardize format across examples');
    }

    return {
      overallScore: Object.values(scores).reduce((a,b) => a+b) / 5,
      breakdown: scores,
      recommendations: recommendations,
      isOptimal: recommendations.length === 0
    };
  }

  generateOptimalSet(task, data) {
    // Algorithme pour sélectionner les exemples optimaux
    const selected = [];

    // 1. Ajouter cas typique (centroid)
    selected.push(this.findCentroid(data));

    // 2. Ajouter cas extrêmes (boundary)
    selected.push(...this.findBoundaries(data, 2));

    // 3. Ajouter cas ambigu si nécessaire
    if (task.hasAmbiguity) {
      selected.push(this.findMostAmbiguous(data));
    }

    // 4. Ordonner par complexité
    return this.orderByComplexity(selected);
  }
}

// Smart Extraction System
class SmartDataExtractor {
  constructor(schema) {
    this.schema = schema;
    this.examples = [];
    this.rules = {};
  }

  // Construire le prompt optimal
  buildExtractionPrompt(document) {
    const prompt = [];

    // 1. Définition du schéma
    prompt.push('Extract data according to this schema:');
    prompt.push(JSON.stringify(this.schema, null, 2));

    // 2. Règles spécifiques
    prompt.push('\nExtraction Rules:');
    for (let [field, rule] of Object.entries(this.rules)) {
      prompt.push(`- ${field}: ${rule}`);
    }

    // 3. Few-shot examples
    prompt.push('\nExamples of correct extraction:');
    this.examples.forEach((ex, i) => {
      prompt.push(`\nExample ${i+1}:`);
      prompt.push('Input: ' + ex.input);
      prompt.push('Output: ' + JSON.stringify(ex.output));
    });

    // 4. Document à traiter
    prompt.push('\nNow extract from this document:');
    prompt.push(document);
    prompt.push('\nOutput (JSON):');

    return prompt.join('\n');
  }

  // Validation du résultat
  validateExtraction(result) {
    const errors = [];
    const warnings = [];

    // Vérifier required fields
    for (let field of this.schema.required) {
      if (!result[field]) {
        errors.push(`Missing required field: ${field}`);
      }
    }

    // Vérifier types
    for (let [field, value] of Object.entries(result)) {
      if (!this.validateType(value, this.schema.fields[field].type)) {
        warnings.push(`Type mismatch: ${field}`);
      }
    }

    // Calculer confidence
    const confidence = 1 - (errors.length * 0.2 + warnings.length * 0.1);

    return {
      valid: errors.length === 0,
      errors,
      warnings,
      confidence: Math.max(0, confidence)
    };
  }
}

